import React, { useEffect, useState, useCallback, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import {
  FiDownload,
  FiPlus,
  FiPlay,
  FiMoreVertical,
  FiChevronLeft,
  FiChevronRight,
  FiEye,
  FiCopy,
  FiExternalLink,
} from 'react-icons/fi';
import { fetchDashboardKpis, fetchLatestMetrics } from '../services/api';

const PAGE_SIZE = 8;

function fmtCount(n) {
  return Math.max(0, Number(n) || 0).toLocaleString();
}

function engagementPct(row) {
  const v = Math.max(1, Number(row.views) || 0);
  const eng = (Number(row.likes) || 0) + (Number(row.shares) || 0) + (Number(row.saves) || 0);
  return ((eng / v) * 100).toFixed(2);
}

function shareRate(row) {
  const v = Math.max(1, Number(row.views) || 0);
  return `${(((Number(row.shares) || 0) / v) * 100).toFixed(1)}%`;
}

function saveRate(row) {
  const v = Math.max(1, Number(row.views) || 0);
  return `${(((Number(row.saves) || 0) / v) * 100).toFixed(1)}%`;
}

function CreatorAvatar({ name }) {
  const initials = String(name || '?')
    .split(/\s+/)
    .filter(Boolean)
    .slice(0, 2)
    .map((w) => w[0])
    .join('')
    .toUpperCase()
    .slice(0, 2);
  return <div className="video-tracking-creator-avatar">{initials || '?'}</div>;
}

function KpiCard({ label, value, sub, tone }) {
  return (
    <div className={`stat-card stat-card--compact stat-card--${tone}`}>
      <div className="stat-card-accent" aria-hidden />
      <div className="label">{label}</div>
      <div className="value">{value}</div>
      {sub && <div className="stat-sub">{sub}</div>}
    </div>
  );
}

export default function VideoTrackingTab() {
  const navigate = useNavigate();
  const [kpis, setKpis] = useState(null);
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  /** { id: row key, top, right } for fixed portal menu */
  const [menuAnchor, setMenuAnchor] = useState(null);

  const load = useCallback(() => {
    setLoading(true);
    Promise.all([fetchDashboardKpis(), fetchLatestMetrics()])
      .then(([kpiRes, latest]) => {
        setKpis(kpiRes.data);
        setRows(latest.data || []);
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => {
    load();
    const onUp = () => load();
    window.addEventListener('videos-updated', onUp);
    return () => window.removeEventListener('videos-updated', onUp);
  }, [load]);

  const totalPages = Math.max(1, Math.ceil(rows.length / PAGE_SIZE));
  const pageClamped = Math.min(page, totalPages);
  const sliceStart = (pageClamped - 1) * PAGE_SIZE;
  const pageRows = useMemo(
    () => rows.slice(sliceStart, sliceStart + PAGE_SIZE),
    [rows, sliceStart]
  );

  useEffect(() => {
    setPage(1);
  }, [rows.length]);

  const activeMenuRow = useMemo(
    () => (menuAnchor ? rows.find((r) => String(r._id) === menuAnchor.id) : null),
    [rows, menuAnchor]
  );

  useEffect(() => {
    if (menuAnchor && !activeMenuRow) setMenuAnchor(null);
  }, [menuAnchor, activeMenuRow]);

  useEffect(() => {
    if (!menuAnchor) return;
    const onDoc = (e) => {
      if (
        e.target.closest?.('.video-tracking-menu-root') ||
        e.target.closest?.('.video-tracking-dropdown-portal')
      ) {
        return;
      }
      setMenuAnchor(null);
    };
    const onScroll = () => setMenuAnchor(null);
    const onKey = (e) => {
      if (e.key === 'Escape') setMenuAnchor(null);
    };
    document.addEventListener('mousedown', onDoc);
    window.addEventListener('scroll', onScroll, true);
    document.addEventListener('keydown', onKey);
    return () => {
      document.removeEventListener('mousedown', onDoc);
      window.removeEventListener('scroll', onScroll, true);
      document.removeEventListener('keydown', onKey);
    };
  }, [menuAnchor]);

  const exportCsv = () => {
    if (!rows.length) {
      toast.error('No data to export');
      return;
    }
    const headers = [
      'url',
      'creator',
      'campaign',
      'platform',
      'views',
      'likes',
      'shares',
      'saves',
      'engagement_pct',
    ];
    const lines = rows.map((r) => {
      const v = r.video || {};
      const url = (r.url || v.url || '').replace(/"/g, '""');
      const creator = (v.influencerName || v.creator || '').replace(/"/g, '""');
      const camp = (v.campaign || '').replace(/"/g, '""');
      const plat = (v.platform || '').replace(/"/g, '""');
      return `"${url}","${creator}","${camp}","${plat}",${r.views},${r.likes},${r.shares},${r.saves || 0},${engagementPct(r)}`;
    });
    const csv = [headers.join(','), ...lines].join('\n');
    const blob = new Blob([csv], {
      type: 'text/csv;charset=utf-8',
    });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `video-tracking-${new Date().toISOString().slice(0, 10)}.csv`;
    a.click();
    URL.revokeObjectURL(a.href);
    toast.success('CSV downloaded');
  };

  const downloadPerformanceReport = () => {
    if (!rows.length) {
      toast.error('No data to include in the report');
      return;
    }
    const wow = overview?.wowGrowth;
    const wowLine =
      wow == null ? '—' : `${wow >= 0 ? '+' : ''}${Number(wow).toFixed(1)}%`;
    const generated = new Date().toISOString();
    const out = [];
    out.push('VIDEO PERFORMANCE REPORT');
    out.push(`Generated (UTC): ${generated}`);
    out.push('');
    out.push('SUMMARY');
    if (overview) {
      out.push(`  Total videos: ${fmtCount(overview.totalVideos)}`);
      out.push(`  Total views: ${fmtCount(overview.totalViews)}`);
      out.push(`  Avg engagement rate: ${overview.avgEngagementRate}%`);
      out.push(`  WoW views growth: ${wowLine}`);
    } else {
      out.push('  (Overview unavailable)');
    }
    out.push('');
    out.push('VIDEOS');
    rows.forEach((r, i) => {
      const v = r.video || {};
      const url = (r.url || v.url || '').trim();
      const creator = v.influencerName || v.creator || '—';
      const camp = v.campaign || '—';
      out.push(`  ${i + 1}. ${creator}`);
      out.push(`     Campaign: ${camp}`);
      out.push(`     URL: ${url || '—'}`);
      out.push(
        `     Views: ${fmtCount(r.views)} | Engagement: ${engagementPct(r)}% | Shares: ${fmtCount(r.shares)} | Saves: ${fmtCount(r.saves || 0)}`
      );
    });
    const blob = new Blob([out.join('\n')], { type: 'text/plain;charset=utf-8' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `video-performance-report-${new Date().toISOString().slice(0, 10)}.txt`;
    a.click();
    URL.revokeObjectURL(a.href);
    toast.success('Report downloaded');
  };

  const copyUrl = async (url) => {
    const u = String(url || '').trim();
    if (!u) {
      toast.error('No URL on this row');
      return;
    }
    try {
      await navigator.clipboard.writeText(u);
      toast.success('Link copied');
    } catch {
      toast.error('Could not copy — copy manually from the video page');
    }
  };

  const openUrlTab = (url) => {
    const u = String(url || '').trim();
    if (!u) {
      toast.error('No URL on this row');
      return;
    }
    window.open(u, '_blank', 'noopener,noreferrer');
  };

  const wow = overview?.wowGrowth;
  const wowStr =
    wow == null ? '—' : `${wow >= 0 ? '+' : ''}${Number(wow).toFixed(1)}%`;

  return (
    <div className="video-tracking">
      <div className="video-tracking-header">
        <div>
          <h2 className="video-tracking-title">Video performance tracking</h2>
          <p className="video-tracking-lead muted-caption">
            Analyze engagement across tracked TikTok and Instagram posts.
          </p>
        </div>
        <div className="video-tracking-header-actions">
          <button type="button" className="btn btn-secondary video-tracking-btn-icon" onClick={exportCsv}>
            <FiDownload size={16} />
            Export CSV
          </button>
          <button
            type="button"
            className="btn btn-primary"
            onClick={downloadPerformanceReport}
          >
            <FiPlus size={16} />
            New report
          </button>
        </div>
      </div>

      {loading ? (
        <div className="stats-row stats-row-overview">
          {[1, 2, 3, 4].map((i) => (
            <div key={i} className="stat-card stat-card-skeleton" aria-hidden />
          ))}
        </div>
      ) : (
        <div className="stats-row stats-row video-tracking-kpis">
          <KpiCard
            tone="videos"
            label="Total videos"
            value={overview ? fmtCount(overview.totalVideos) : '—'}
          />
          <KpiCard
            tone="views"
            label="Total views"
            value={overview ? fmtCount(overview.totalViews) : '—'}
          />
          <KpiCard
            tone="engagement"
            label="Avg engagement"
            value={overview ? `${overview.avgEngagementRate}%` : '—'}
            sub="(likes + shares + saves) ÷ views"
          />
          <KpiCard
            tone="growth"
            label="WoW (views)"
            value={wowStr}
            sub="vs prior 7 days"
          />
        </div>
      )}

      {/* <div className="video-tracking-filters">
        <button type="button" className="video-tracking-filter-chip">
          <FiCalendar size={16} />
          <span>Last 30 days</span>
          <FiChevronDown size={16} />
        </button>
        <button type="button" className="video-tracking-filter-chip">
          <span className="video-tracking-filter-muted">Platform:</span>
          <span>All</span>
          <FiChevronDown size={16} />
        </button>
        <button type="button" className="video-tracking-filter-chip">
          <span className="video-tracking-filter-muted">Campaign:</span>
          <span>All</span>
          <FiChevronDown size={16} />
        </button>
        <span className="video-tracking-filter-divider" aria-hidden />
        <button type="button" className="video-tracking-clear">
          Clear filters
        </button>
        <div className="video-tracking-bulk">
          <span className="video-tracking-bulk-label">Bulk actions</span>
          <select className="video-tracking-select" aria-label="Bulk action">
            <option>Select action</option>
            <option>Compare videos</option>
            <option>Assign to campaign</option>
            <option>Archive</option>
          </select>
        </div>
      </div> */}

      <div className="video-tracking-table-card">
        <div className="table-wrap video-tracking-table-wrap">
          <table className="video-tracking-table">
            <thead>
              <tr>
                <th className="video-tracking-th-check">
                  <input type="checkbox" aria-label="Select all" disabled />
                </th>
                <th>Video</th>
                <th>Creator</th>
                <th>Campaign</th>
                <th className="video-tracking-th-num">Views</th>
                <th className="video-tracking-th-num">Engagement</th>
                <th className="video-tracking-th-num">Shares</th>
                <th className="video-tracking-th-num">Saves</th>
                <th className="video-tracking-th-actions">Actions</th>
              </tr>
            </thead>
            <tbody>
              {!loading && rows.length === 0 && (
                <tr>
                  <td colSpan={9} className="video-tracking-empty">
                    No metrics yet. Add videos and run a scrape.
                  </td>
                </tr>
              )}
              {pageRows.map((r) => {
                const v = r.video || {};
                const rowKey = String(r._id);
                const rowUrl = (r.url || v.url || '').trim();
                const title =
                  (v.influencerName || v.creator || 'Video').slice(0, 48) ||
                  'Untitled';
                const creatorName = v.influencerName || v.creator || '—';
                return (
                  <tr
                    key={rowKey}
                    className="video-tracking-row"
                    onClick={() => navigate(`/video/${r._id}`)}
                  >
                    <td onClick={(e) => e.stopPropagation()}>
                      <input type="checkbox" aria-label="Select row" disabled />
                    </td>
                    <td>
                      <div className="video-tracking-video-cell">
                        <div className="video-tracking-thumb">
                          <FiPlay className="video-tracking-thumb-play" size={18} />
                        </div>
                        <div>
                          <div className="video-tracking-title-cell">{title}</div>
                          <div className="video-tracking-meta-row">
                            {v.platform && (
                              <span className={`badge badge-${v.platform}`}>{v.platform}</span>
                            )}
                            <span className="video-tracking-url-hint">
                              {(r.url || v.url || '').slice(0, 42)}
                              {(r.url || v.url || '').length > 42 ? '…' : ''}
                            </span>
                          </div>
                        </div>
                      </div>
                    </td>
                    <td>
                      <div className="video-tracking-creator-cell">
                        <CreatorAvatar name={creatorName} />
                        <span>{creatorName}</span>
                      </div>
                    </td>
                    <td>
                      <span className="video-tracking-campaign">{v.campaign || '—'}</span>
                    </td>
                    <td className="video-tracking-num">{fmtCount(r.views)}</td>
                    <td className="video-tracking-num">
                      <span className="video-tracking-eng-rate">{engagementPct(r)}%</span>
                      <div className="video-tracking-sub-num">{fmtCount(r.likes)} likes</div>
                    </td>
                    <td className="video-tracking-num">
                      <span>{fmtCount(r.shares)}</span>
                      <div className="video-tracking-sub-num">{shareRate(r)}</div>
                    </td>
                    <td className="video-tracking-num">
                      <span className="video-tracking-saves">{fmtCount(r.saves)}</span>
                      <div className="video-tracking-sub-num video-tracking-sub-num--coral">
                        {saveRate(r)}
                      </div>
                    </td>
                    <td className="video-tracking-actions" onClick={(e) => e.stopPropagation()}>
                      <div className="video-tracking-menu-root">
                        <button
                          type="button"
                          className="video-tracking-more"
                          aria-expanded={menuAnchor?.id === rowKey}
                          aria-haspopup="menu"
                          aria-label="Row actions"
                          onClick={(e) => {
                            e.stopPropagation();
                            const btn = e.currentTarget;
                            const rect = btn.getBoundingClientRect();
                            setMenuAnchor((prev) =>
                              prev?.id === rowKey
                                ? null
                                : {
                                    id: rowKey,
                                    top: rect.bottom + 4,
                                    right: window.innerWidth - rect.right,
                                  }
                            );
                          }}
                        >
                          <FiMoreVertical size={18} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        {rows.length > 0 && (
          <div className="video-tracking-pagination">
            <span className="muted-caption video-tracking-page-info">
              Showing{' '}
              <strong>
                {sliceStart + 1} – {Math.min(sliceStart + PAGE_SIZE, rows.length)}
              </strong>{' '}
              of {rows.length} videos
            </span>
            <div className="video-tracking-page-btns">
              <button
                type="button"
                className="video-tracking-page-btn"
                disabled={pageClamped <= 1}
                onClick={() => setPage((p) => Math.max(1, p - 1))}
                aria-label="Previous page"
              >
                <FiChevronLeft size={18} />
              </button>
              <span className="video-tracking-page-label">
                Page {pageClamped} of {totalPages}
              </span>
              <button
                type="button"
                className="video-tracking-page-btn"
                disabled={pageClamped >= totalPages}
                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                aria-label="Next page"
              >
                <FiChevronRight size={18} />
              </button>
            </div>
          </div>
        )}
      </div>

      {menuAnchor &&
        activeMenuRow &&
        createPortal(
          <ul
            className="video-tracking-dropdown video-tracking-dropdown-portal"
            role="menu"
            style={{
              position: 'fixed',
              top: menuAnchor.top,
              right: menuAnchor.right,
              zIndex: 2000,
            }}
          >
            <li role="none">
              <button
                type="button"
                className="video-tracking-dropdown-item"
                role="menuitem"
                onClick={() => {
                  setMenuAnchor(null);
                  navigate(`/video/${activeMenuRow._id}`);
                }}
              >
                <FiEye size={16} aria-hidden />
                View details
              </button>
            </li>
            <li role="none">
              <button
                type="button"
                className="video-tracking-dropdown-item"
                role="menuitem"
                disabled={!(activeMenuRow.url || activeMenuRow.video?.url || '').trim()}
                onClick={() => {
                  setMenuAnchor(null);
                  const u = (
                    activeMenuRow.url ||
                    activeMenuRow.video?.url ||
                    ''
                  ).trim();
                  copyUrl(u);
                }}
              >
                <FiCopy size={16} aria-hidden />
                Copy link
              </button>
            </li>
            <li role="none">
              <button
                type="button"
                className="video-tracking-dropdown-item"
                role="menuitem"
                disabled={!(activeMenuRow.url || activeMenuRow.video?.url || '').trim()}
                onClick={() => {
                  setMenuAnchor(null);
                  const u = (
                    activeMenuRow.url ||
                    activeMenuRow.video?.url ||
                    ''
                  ).trim();
                  openUrlTab(u);
                }}
              >
                <FiExternalLink size={16} aria-hidden />
                Open in new tab
              </button>
            </li>
          </ul>,
          document.body
        )}
    </div>
  );
}
